main {
  display: flex;
}
.content {
  position: relative;
  flex: 1;
}
.result-popup {
  position: absolute;
  top: 50%;
  left: 65%;
  width: 50%;
  height: 80%;
  transform: translate(-50%, -50%);
  max-width: 100%;
  max-height: 100%;
  background: #fff;
}
.result-popup > img {
  width: 100%;
  height: 100%;
  object-fit: contain;
}
.result-popup > button {
  position: absolute;
  border: none;
  background: #F3463D;
  color: #ffffff;
  font-size: 15px;
  width: 30px;
  height: 30px;
  border-radius: 8px;
  right: 10px;
  top: 10px;
}
.result-popup > button:hover {
  cursor: pointer;
  opacity: 0.7;
}
</style>
